import { getSession } from '@/infrastructure/auth/getServerSession';
import { redirect } from 'next/navigation';
import ResidenteReservas from '@/presentation/components/ResidenteReservas';

export default async function ResidenteHome() {
    const session = await getSession();

    if (!session?.user || session.user.rol !== 'Residente') {
        redirect('/login');
    }

    return (
        <div style={{ padding: '2rem', color: 'white' }}>
            <h1>Portal del Residente</h1>
            <p>Bienvenido, {session.user.rol} (ID: {session.user.id}).</p>

            <div style={{ marginTop: '20px', padding: '20px', background: 'rgba(255,255,255,0.05)', borderRadius: '12px' }}>
                <ResidenteReservas />
            </div>

            <form action="/api/auth/logout" method="POST" style={{ marginTop: '20px' }}>
                <button type="submit" style={{ padding: '10px 20px', background: '#ef4444', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>
                    Cerrar Sesión
                </button>
            </form>
        </div>
    );
}
